import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.map.js";
import "core-js/modules/web.url-search-params.delete.js";
import "core-js/modules/web.url-search-params.has.js";
import "core-js/modules/web.url-search-params.size.js";
import { dFiles, DFile } from '@/idb/db';
import { LangPack } from './lang';
export default {
  name: 'OSIDirDigger',
  props: {
    windowId: {
      type: String,
      required: true
    },
    USERID: {
      type: Number,
      default: 0
    }
  },
  data() {
    return {
      LangData: {},
      currentFolder: null,
      currentPath: [],
      contents: [],
      selectedItem: null,
      fileInput: null,
      filterType: null,
      // для фильтрации по типу
      visibleMode: 'tile',
      //tile || table
      contentSortMode: 'up',
      //up || down
      contentSortKey: 'name',
      sortKeys: ['name', 'type', 'extension', 'size', 'createdAt', 'updatedAt']
    };
  },
  computed: {
    // Отфильтрованное содержимое
    // filteredContents() {
    //     if (!this.filterType) return this.contents;
    //     return this.contents.filter(item => item.type === this.filterType);
    // },
    filteredContents() {
      let items = this.contents;

      // Фильтрация
      if (this.filterType) {
        items = items.filter(item => item.type === this.filterType);
      }

      // Сортировка
      return items.sort((a, b) => {
        let aVal = a[this.contentSortKey];
        let bVal = b[this.contentSortKey];
        if (this.contentSortKey === 'name') {
          aVal = aVal.toLowerCase();
          bVal = bVal.toLowerCase();
        }
        if (this.contentSortMode === 'up') {
          return aVal > bVal ? 1 : -1;
        } else {
          return aVal < bVal ? 1 : -1;
        }
      });
    }
  },
  methods: {
    // Эмиттить событие для глобального обработчика
    showError(message) {
      this.$emit('error', message);
    },
    // Загрузка корневой папки
    async loadRootFolder() {
      try {
        const Root = await dFiles.getRoot(this.USERID);
        this.currentFolder = Root;
        this.filterType = null;
        await this.loadFolderContents(Root.id);
        this.currentPath = [Root];
        this.selectedItem = null;
      } catch (error) {
        this.showError(`Ошибка загрузки: ${error.message}`);
      }
    },
    Converter_dateTime(inpDate) {
      return inpDate.toLocaleTimeString('ru-RU', {
        hour: '2-digit',
        minute: '2-digit',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
      });
    },
    // Навигация по папкам
    async navigateTo(folder) {
      if (folder.type !== 'folder') return;
      this.currentFolder = folder;
      await this.loadFolderContents(folder.id);

      // Обновляем путь
      const pathIndex = this.currentPath.findIndex(p => p.id === folder.id);
      if (pathIndex !== -1) {
        this.currentPath = this.currentPath.slice(0, pathIndex + 1);
      } else {
        this.currentPath.push(folder);
      }
    },
    // Создание новой папки
    async createNewFolder() {
      const folderName = prompt(this.LangData.enter_folder_name || 'Введите имя папки:');
      if (!folderName) return;
      try {
        await dFiles.createFolder(this.USERID, this.currentFolder.id, folderName);
        await this.loadFolderContents(this.currentFolder.id);
      } catch (error) {
        console.error('Error creating folder:', error);
        alert(error.message);
      }
    },
    // Загрузка файлов
    uploadFiles() {
      if (this.fileInput) {
        this.fileInput.click();
      }
    },
    async handleFileUpload(event) {
      const files = Array.from(event.target.files);
      try {
        for (const file of files) {
          const fileData = {
            name: file.name,
            size: file.size,
            type: file.type,
            metadata: await this.extractMetadata(file)
          };
          await dFiles.addFile(this.USERID, this.currentFolder.id, fileData, file);
        }
        await this.loadFolderContents(this.currentFolder.id);
      } catch (error) {
        console.error('Error uploading files:', error);
        alert('Ошибка при загрузке файлов');
      }
      event.target.value = ''; // Сбрасываем input
    },
    // Извлечение метаданных из файла
    async extractMetadata(file) {
      // Для изображений
      if (file.type.startsWith('image/')) {
        return new Promise(resolve => {
          const img = new Image();
          img.onload = () => {
            resolve({
              width: img.width,
              height: img.height
            });
          };
          img.onerror = () => resolve({});
          img.src = URL.createObjectURL(file);
        });
      }

      // Для аудио (можно добавить позже)
      return {};
    },
    // Выбор элемента
    selectItem(item) {
      this.selectedItem = item;
    },
    // Открытие элемента (папки или файла)
    async openItem(item) {
      if (item.type === 'folder') {
        await this.navigateTo(item);
      } else {
        // Здесь можно открыть файл в соответствующем приложении
        console.log('Open file:', item);
        this.openFileInApp(item);
      }
    },
    // Открытие файла в приложении
    openFileInApp(file) {
      // Эмитим событие для открытия файла в соответствующем приложении
      this.$emit('open-file', {
        file: file,
        app: this.getAppForFile(file)
      });
    },
    // Определение приложения для файла
    getAppForFile(file) {
      const appMap = {
        'audio': 'osimplayer',
        'text': 'ositexteditor',
        'image': 'osipicta'
      };
      return appMap[file.type] || null;
    },
    // Обрезка длинных имен
    truncateName(name, maxLength = 15) {
      if (name.length <= maxLength) return name;
      return name.substr(0, maxLength - 3) + '...';
    },
    // Форматирование размера
    formatSize(bytes) {
      if (bytes === 0) return '0 B';
      const k = 1024;
      const sizes = ['B', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    },
    // Навигация в домашнюю папку
    async navigateToHome() {
      // Можно создать папку "Документы" если её нет
      const docsFolder = this.contents.find(c => c.type === 'folder' && c.name === 'Documents');
      if (docsFolder) {
        await this.navigateTo(docsFolder);
      }
    },
    // Для отображения изображения
    getImageUrl(item) {
      if (item.blob) {
        // Создаем URL из Blob
        return URL.createObjectURL(item.blob);
      }
      return null;
    },
    // Освобождаем URL когда они больше не нужны
    revokeImageUrl(item) {
      if (item._objectUrl) {
        URL.revokeObjectURL(item._objectUrl);
        item._objectUrl = null;
      }
    },
    // Загрузка содержимого папки с обработкой URL
    async loadFolderContents(folderId) {
      // Освобождаем старые URL
      this.contents.forEach(item => {
        if (item._objectUrl) {
          URL.revokeObjectURL(item._objectUrl);
        }
      });
      const items = await dFiles.getFolderContents(this.USERID, folderId);
      this.contents = items.map(item => {
        const dFile = new DFile(item);
        if (dFile.type === 'image' && dFile.blob) {
          dFile._objectUrl = URL.createObjectURL(dFile.blob);
        }
        return dFile;
      });
    },
    // Получение иконки в зависимости от типа
    getFileIcon(item) {
      const iconClassMap = {
        folder: 'bi-folder-fill',
        image: 'bi-image-fill',
        audio: 'bi-file-music-fill',
        archive: 'bi-file-earmark-zip-fill',
        video: 'bi-film',
        file: 'bi-file-earmark-fill',
        app: 'bi-gear-wide-connected'
      };
      return iconClassMap[item] || '';
    },
    // сброс фильтра отображения
    showAll() {
      this.filterType = null;
    },
    // Фильтрация содержимого (для левого меню)
    showImagesOnly() {
      this.filterType = 'image';
    },
    showTextOnly() {
      this.filterType = 'text';
    },
    showAudioOnly() {
      this.filterType = 'audio';
    },
    // смена режима отображения содержимого папки
    Chng_visibleMode() {
      this.visibleMode = this.visibleMode == 'tile' ? 'table' : 'tile';
    },
    // получить строковое наименование типа
    Get_strFileTypeName(typeVal) {
      switch (typeVal) {
        case 'folder':
          return this.LangData.typefilefolder;
        case 'audio':
          return this.LangData.typefileaudion;
        case 'image':
          return this.LangData.typefileimage;
        case 'video':
          return this.LangData.typefilevideo;
        case 'archive':
          return this.LangData.typefilearchive;
        case 'file':
          return this.LangData.typefilefile;
        default:
          return typeVal;
      }
    },
    // изменение сортировки: убыв. / возрастание
    Chng_contentSortMode() {
      this.contentSortMode = this.contentSortMode == 'up' ? 'down' : 'up';
    },
    // Очистка перед уничтожением компонента
    beforeDestroy() {
      if (this.contents) {
        this.contents.forEach(item => this.revokeImageUrl(item));
      }
    }
  },
  async mounted() {
    console.log(`OSIDirDigger mounted with windowId:`, this.windowId);
    const userLang = navigator.language || navigator.userLanguage;
    const userLangS = userLang.split('-')[0];
    this.UserLang = userLangS;
    const LangPackData = LangPack;
    this.LangData = userLangS && LangPackData && LangPackData[userLangS] ? LangPackData[userLangS] : LangPackData.en;

    // Сохраняем ссылку на fileInput
    this.fileInput = this.$refs.fileInput;
    await this.loadRootFolder();
  }
};
